import 'dart:io'; import 'package:flutter_riverpod/flutter_riverpod.dart'; import '../../../../core/di/injection.dart'; import '../../../auth/presentation/providers/auth_providers.dart'; import '../../domain/entities/report.dart'; import '../../domain/repositories/report_repository.dart';
final reportRepositoryProvider=Provider<ReportRepository>((ref)=>sl<ReportRepository>()); final myReportsProvider=StreamProvider<List<Report>>((ref){final user=ref.watch(currentUserProvider); if(user==null)return const Stream.empty(); return ref.watch(reportRepositoryProvider).watchMyReports(reporterId:user.uid);}); final pendingReportsProvider=StreamProvider<List<Report>>((ref)=>ref.watch(reportRepositoryProvider).watchPendingReports()); final reportDetailProvider=FutureProvider.family<Report?,String>((ref,id)=>ref.watch(reportRepositoryProvider).getReport(id)); final reportControllerProvider=StateNotifierProvider<ReportController,ReportControllerState>((ref)=>ReportController(ref));
class ReportController extends StateNotifier<ReportControllerState>{final Ref ref; ReportController(this.ref):super(const ReportControllerState()); Future<String?> submitReport({required String targetId,required ReportTargetType targetType,required ReportReason reason,required String description,List<File> evidenceImages=const[]}) async{final user=ref.read(currentUserProvider); if(user==null){state=state.failure('Login required');return null;} state=state.loading(); try{final id=await ref.read(reportRepositoryProvider).createReport(reporterId:user.uid,targetId:targetId,targetType:targetType,reason:reason,description:description,evidenceImages:evidenceImages); state=state.successState(reportId:id); ref.invalidate(myReportsProvider); return id;}catch(e){state=state.failure(e.toString());return null;}}}
class ReportControllerState{final bool isLoading,success; final String? reportId,errorMessage; const ReportControllerState({this.isLoading=false,this.success=false,this.reportId,this.errorMessage}); ReportControllerState loading()=>const ReportControllerState(isLoading:true); ReportControllerState successState({String? reportId})=>ReportControllerState(success:true,reportId:reportId); ReportControllerState failure(String m)=>ReportControllerState(errorMessage:m);}
